const query = ($json && $json.query) ? $json.query : {};
const requested = String(query.period || '30d');
const validPeriods = { '7d': 7, '30d': 30, '90d': 90 };
const days = validPeriods[requested] || 30;
const today = new Date();
const rows = [];

for (let i = days - 1; i >= 0; i -= 1) {
  const date = new Date(today);
  date.setDate(today.getDate() - i);

  const weekDay = date.getDay();
  const weekendFactor = (weekDay === 0 || weekDay === 6) ? 0.72 : 1;
  const trendFactor = 1 + ((days - i) / days) * 0.22;
  const noiseFactor = 0.9 + ((i % 5) * 0.04);

  const cliques = Math.round(100 * weekendFactor * trendFactor * noiseFactor);
  const impressoes = Math.round(cliques * (12 + (i % 4)));
  const custo = Number((cliques * (2.15 + (i % 3) * 0.18)).toFixed(2));
  const conversoes = Math.round(cliques * (0.08 + (i % 6) * 0.003));

  rows.push({
    data: date.toISOString().slice(0, 10),
    cliques,
    impressoes,
    custo,
    conversoes
  });
}

return [{ json: rows }];

const body = ($json && $json.body && typeof $json.body === 'object') ? $json.body : {};
const campaigns = Array.isArray(body.campaigns) ? body.campaigns : [];
const performance = Array.isArray(body.performance) ? body.performance : [];

const totalClicks = performance.reduce((acc, item) => acc + Number(item.cliques || 0), 0);
const totalConversions = performance.reduce((acc, item) => acc + Number(item.conversoes || 0), 0);
const totalCost = performance.reduce((acc, item) => acc + Number(item.custo || 0), 0);
const conversionRate = totalClicks > 0 ? (totalConversions / totalClicks) * 100 : 0;

const pausedCampaigns = campaigns.filter((item) => String(item.status || '').toLowerCase() === 'pausada');
const lowVolumeCampaigns = campaigns.filter((item) => Number(item.cliques || 0) < 300);

const insights = [];

if (conversionRate < 5) {
  insights.push({
    id: 'ins-1',
    titulo: 'Conversao abaixo da meta',
    recomendacao: 'Ajuste termos de pesquisa e inclua extensoes de chamada para aumentar intencao de clique qualificado.',
    impacto: 'ROI',
    prioridade: 'alta'
  });
}

if (totalCost > 4000) {
  insights.push({
    id: 'ins-2',
    titulo: 'Custo elevado no periodo',
    recomendacao: 'Redistribua orcamento para campanhas com maior taxa de conversao e reduza grupos com CPC acima da media.',
    impacto: 'Orcamento',
    prioridade: 'media'
  });
}

if (pausedCampaigns.length > 0) {
  insights.push({
    id: 'ins-3',
    titulo: 'Campanhas pausadas detectadas',
    recomendacao: `Revise ${pausedCampaigns.length} campanha(s) pausada(s) para recuperar volume sem comprometer CPA.`,
    impacto: 'Lances',
    prioridade: 'media'
  });
}

if (lowVolumeCampaigns.length > 0) {
  insights.push({
    id: 'ins-4',
    titulo: 'Baixo volume de cliques em parte das campanhas',
    recomendacao: 'Teste novos criativos e variacoes de publico para ampliar alcance em campanhas de baixo volume.',
    impacto: 'Criativos',
    prioridade: 'baixa'
  });
}

if (insights.length === 0) {
  insights.push({
    id: 'ins-default',
    titulo: 'Performance estavel',
    recomendacao: 'Mantenha a estrategia atual e monitore variacoes de CPC e conversao semanalmente.',
    impacto: 'ROI',
    prioridade: 'baixa'
  });
}

return [{ json: insights }];
